import {
  workflow,
  node,
  trigger,
  expr,
} from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: {
    name: 'When clicking "Execute workflow"',
  },
});

const approvalTest = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'approval test',
    parameters: {
      mode: 'manual',
      includeOtherFields: false,
      fields: {
        values: [
          {
            name: 'status',
            type: 'stringValue',
            value: 'approved',
          },
        ],
      },
    },
  },
});

export default workflow('', 'approval test')
  .add(manualTrigger)
  .to(approvalTest);
